var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"어이, 뭘 하고 있나, 친구? 별이라도 세고 있는 거야?","JPN":"おい、何をしてるんだ？　星でも数えてるのか？","ENG":"Hey, what's up buddy? You counting the stars or something?","TWN":"喂，你在幹什麼啊，朋友？數星星？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"별은 위협적이지 않다. 수를 세는 일도 전술적으로 필요하지 않다.","JPN":"星は威嚇しない。数を数えるのも、戦術的に必要ない。","ENG":"The celestial bodies you call stars are not an immediate threat. Therefore, counting their quantity is tactically unnecessary.","TWN":"星星沒有威脅性。這種行為也沒有任何戰略意義。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"거, 재미없기는. 그럴 땐 이렇게 대답하는 거야.","JPN":"つまらないな。そういう時は、こういう風に答えるんだ。","ENG":"Ugh, how boring. This is how you ought to respond.","TWN":"唉，真無趣。我就知道你會這樣回答。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"박사의 연약한 단백질 하드웨어로 생각할 만한 하찮은 일이로군!","JPN":"いかにも博士の軟弱なタンパク質ハードウェアが考えそうなことだ！","ENG":"Only a frail creature comprised of protein-based hardware would think of such petty musings!","TWN":"但這就是博士會用他脆弱的蛋白質硬體思考的小事！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"나의 강인한 155mm 아틀라틀 포신과 메인 카메라는 언제나 침식체의 도발을 경계하고 있다네!","JPN":"吾輩の強靭な155mmアトラトル砲身とメインカメラは、常に侵食体の挑発を警戒している！","ENG":"My potent 155 mm Atlatl gun and main camera are always on the lookout for the provocation of Corrupted Objects!","TWN":"我強韌的155mm阿特拉托機槍炮和主相機隨時都在警戒著侵蝕體！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"어때, 이 정도는 되야 세기말 결전병기 느낌이 나지 않겠나.","JPN":"よし、これで世紀末決戦兵器らしくなった。","ENG":"Now that sounds more like a real Ultimate Doomsday Weapon., don't you think?","TWN":"怎麼樣？這樣說才有世紀末決戰兵器的感覺吧。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"의미를 알 수 없다.","JPN":"意味がわからない。","ENG":"That does not compute.","TWN":"意義不明。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"지금은 세기말도 아니고, 결전병기라는 분류체계는 존재하지 않는다.","JPN":"今は世紀末でもなく、決戦兵器という分類体系は存在しない。","ENG":"There is no weapon category called Ultimate, and the world is not currently facing Doomsday.","TWN":"現在不是世紀末，武器分類中也沒有決戰兵器。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그건 그저 관용적인 표현일 뿐이다.","JPN":"それは単なる慣用的な表現だ。","ENG":"Your statement is riddled with inherent anachronisms merely for the sake of human romanticism.","TWN":"那只是一種慣用的表達方式。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"물론 그렇긴 하지.","JPN":"もちろん、そうだ。","ENG":"I suppose you're right.","TWN":"你說得沒錯。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"하지만 살다 보면 때로는 그런 관용적인 표현이 더 중요할 때가 있거든.","JPN":"だが、そういう慣用的な表現が大事な時もあるんだ。","ENG":"But then again, romance often becomes the most important part of life.","TWN":"不過，有時候這種表達方式很重要。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"뭐, 언젠가는 너도 깨닫게 될 거야.","JPN":"まあ、いつか君も気づくだろう。","ENG":"You'll see, one day.","TWN":"嗯，總有一天你也會明白的。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"네게 탑재된 인공지능 모듈은 경험이 쌓일수록 계속해서 진화해 나가는 시스템이라고, 엠버 소장이 말했으니까.","JPN":"君に搭載された人工知能モジュールは、\\n経験を重ねるごとに進化するシステムだと、アンバー所長が言っていたからな。","ENG":"Director Ember said the A.I. module in you continues to evolve with experience.","TWN":"琥珀所長說過，你所搭載的人工智慧模組會隨著經驗的積累不斷進化。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"엠버 소장이라면, 당신과 함께 나의 설계를 주도한 사람들 중 하나라고 메모리에 기록되어 있다.","JPN":"アンバー所長なら、教授と一緒に吾輩の設計を主導した人々の一人だと、メモリーに記録されている。","ENG":"Director Ember... My files indicate she was one of the main designers who contributed to my creation, along with you.","TWN":"琥珀所長，參照我的記憶體紀錄，她是和您一起參與設計我的主要人員之一。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하지만 첫 출격 이후 한 번도 만난 적이 없다. 그녀는 어디에 있는 거지?","JPN":"だが、初出撃以来、一度も会ったことがない。彼女はどこにいる？","ENG":"But I never encountered her after my initial deployment. Where is she?","TWN":"但在第一次出擊後，我就再也沒有見過她。她現在在哪？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"아, 그녀는...... 기밀 반출 혐의로 퓨처 앳 워 프로젝트에서 제명됐어.","JPN":"ああ、彼女は……機密漏洩の疑いで、フューチャーアットウォー・プロジェクトから除名された。","ENG":"Oh, you see... She was booted from the Future at War Project for the unauthorized disclosure of classified information.","TWN":"啊，她……因為洩露機密的嫌疑，被天啟兵器計畫除名了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"사람들을 구하기 위해서 어쩔 수 없는 일이었다고 탄원서를 제출했지만, 그놈의 정치적인 문제라는 게 복잡하게 얽혀 있어서 어쩔 수가 없더군.","JPN":"人を救うためには仕方なかったという嘆願書を提出したが、\\n政治的な問題ってやつが複雑で、どうにもならなかった。","ENG":"Although she submitted a justification saying she had no choice in order to save many lives, it all got political and complicated in the end.","TWN":"雖然她提出了請願書，說這是為了救人不得已而為之的事情，但因為那傢伙的政治問題很複雜，所以沒辦法。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그 뒤로는 잠적이라도 했는지 연락이 닿질 않아. 어디서 뭘 하는지 원......","JPN":"その後、行方をくらませて連絡もつかなくなった。どこで何をしてるのか……","ENG":"I guess she decided that she didn't want to be found after that. I can't seem to get in touch with her. I wonder what she's been up to...","TWN":"之後可能是潛逃了吧，我連絡不到她，也不知道她正在哪裡做什麼……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그런데 그건 왜 묻지? 엄마가 그립기라도 한 건가?","JPN":"ところで、なぜ彼女のことを聞いたんだ？　お母さんに会いたいのか？","ENG":"Anyway, why do you ask? Do you miss mommy?","TWN":"不過你問這個幹什麼？難道是想媽媽了？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};